				wildAgent = r
			}
			if !hasAgent && wildNoAgent == nil {
				wildNoAgent = r
			}
		}
	}
	if exactNoAgent != nil {
		return exactNoAgent
	}
	if wildAgent != nil {
		return wildAgent
	}
	return wildNoAgent
}

