// simpleCtx is a test implementation of CheckContext.
type simpleCtx struct {
	evidence     map[string]string
	agentCount   int
	iteration    int
	maxIter      int
	originPhase  string
	commandsRan  map[string]bool
	teammateName string
}

func (c *simpleCtx) Evidence() map[string]string  { return c.evidence }
