func TestEvalCheck_EvidencePass(t *testing.T) {
	c := Check{Type: "evidence", Key: "k", Value: "v", Message: "failed"}
	ctx := &simpleCtx{evidence: map[string]string{"k": "v"}}
	assert.Empty(t, EvalCheck(c, ctx))
}

