		input.AgentID = "teammate-" + input.SessionID
	}

	expectedAgentID := "teammate-" + teammateSessionID
	if input.AgentID != expectedAgentID {
		t.Errorf("synthetic agent_id = %q, want %q", input.AgentID, expectedAgentID)
	}
}

