package config

import (
	"fmt"
	"path"
	"strings"
)

// CheckContext provides the runtime values needed to evaluate guard checks.
type CheckContext interface {
	Evidence() map[string]string
	ActiveAgentCount() int
	Iteration() int
	MaxIterations() int
	// OriginPhase is the phase from which the transition originates.
	// Used by max_iterations to exempt transitions from PLANNING.
	OriginPhase() string
	// CommandsRan tracks which commands have been run (Phase 2 state).
	CommandsRan() map[string]bool
}

// EvalCheck evaluates a single Check against the given context.
// Returns "" if the check passes, or a denial reason string if it fails.
func EvalCheck(check Check, ctx CheckContext) string {
	switch check.Type {
	case "evidence":
		ev := ctx.Evidence()
		// Primary key/value check
		if ev[check.Key] == check.Value {
			return ""
		}
		// Alternatives (OR semantics)
		for _, alt := range check.Alternatives {
			if ev[alt.Key] == alt.Value {
				return ""
			}
		}
		return check.Message

	case "no_active_agents":
		if ctx.ActiveAgentCount() == 0 {
			return ""
		}
		if check.Message != "" {
			return fmt.Sprintf("%s (%d active)", check.Message, ctx.ActiveAgentCount())
		}
		return fmt.Sprintf(
			"cannot leave RESPAWN with %d active teammate(s) — shut down old teammates before spawning new ones",
			ctx.ActiveAgentCount(),
		)

	case "max_iterations":
		// First entry from PLANNING doesn't count as an iteration.
		if ctx.OriginPhase() == "PLANNING" {
			return ""
		}
		if ctx.Iteration()+1 > ctx.MaxIterations() {
			if check.Message != "" {
				return fmt.Sprintf("%s (max: %d)", check.Message, ctx.MaxIterations())
			}
			return fmt.Sprintf(
				"max iterations (%d) reached. Ask the user whether to continue. If yes, run: wf-client reset-iterations <workflow-id>, then retry this transition.",
				ctx.MaxIterations(),
			)
		}
		return ""

	case "command_ran":
		cmds := ctx.CommandsRan()
		// Prefer Category; fall back to Key for backwards compatibility.
		key := check.Category
		if key == "" {
			key = check.Key
		}
		if cmds[key] {
			return ""
		}
		return check.Message

	default:
		return fmt.Sprintf("unknown check type %q", check.Type)
	}
}

// EvalChecks evaluates all checks with AND semantics, short-circuiting on first failure.
// Returns "" if all checks pass, or the first denial reason.
func EvalChecks(checks []Check, ctx CheckContext) string {
	for _, check := range checks {
		if reason := EvalCheck(check, ctx); reason != "" {
			return reason
		}
	}
	return ""
}

// agentGlobMatch returns true if the agent pattern matches the given name.
// Matching is case-insensitive glob using path.Match semantics.
func agentGlobMatch(pattern, name string) bool {
	matched, err := path.Match(strings.ToLower(pattern), strings.ToLower(name))
	return err == nil && matched
}

// FindIdleRule returns the best-matching IdleRule from cfg for the given phase and agentName.
// Priority (highest to lowest):
//  1. Exact phase match + agent glob matches agentName
//  2. Exact phase match + no agent (applies to all agents)
//  3. Wildcard phase ("*") + agent glob matches agentName
//  4. Wildcard phase ("*") + no agent
//
// Returns nil if no rule matches.
func FindIdleRule(cfg *Config, phase, agentName string) *IdleRule {
	var exactNoAgent, wildAgent, wildNoAgent *IdleRule
	for i := range cfg.TeammateIdle {
		r := &cfg.TeammateIdle[i]
		exactPhase := r.Match == phase
		wildcardPhase := r.Match == "*"
		if !exactPhase && !wildcardPhase {
			continue
		}
		hasAgent := r.Agent != ""
		agentMatches := hasAgent && agentGlobMatch(r.Agent, agentName)

		if exactPhase {
			if agentMatches {
				return r // highest priority: exact phase + agent match
			}
			if !hasAgent && exactNoAgent == nil {
				exactNoAgent = r
			}
		} else { // wildcard phase
			if agentMatches && wildAgent == nil {
				wildAgent = r
			}
			if !hasAgent && wildNoAgent == nil {
				wildNoAgent = r
			}
		}
	}
	if exactNoAgent != nil {
		return exactNoAgent
	}
	if wildAgent != nil {
		return wildAgent
	}
	return wildNoAgent
}

// FindGuards returns the GuardRules from cfg that match the given from→to transition.
// Exact matches (no wildcards) are returned before wildcard matches.
// Both from and to can be "*" in rules for wildcard matching.
func FindGuards(cfg *Config, from, to string) []GuardRule {
	var exact, wild []GuardRule
	for _, rule := range cfg.Guards {
		fromMatch := rule.From == from || rule.From == "*"
		toMatch := rule.To == to || rule.To == "*"
		if !fromMatch || !toMatch {
			continue
		}
		if rule.From == "*" || rule.To == "*" {
			wild = append(wild, rule)
		} else {
			exact = append(exact, rule)
		}
	}
	return append(exact, wild...)
}

// Package config provides declarative YAML-based configuration for workflow
// phase transition guards, tracking patterns, and teammate idle rules.
package config

// Config is the top-level configuration structure.
type Config struct {
	Tracking     TrackingConfig `yaml:"tracking"`
	Guards       []GuardRule    `yaml:"guards"`
	TeammateIdle []IdleRule     `yaml:"teammate_idle"`
}

// TrackingConfig maps category name to its tracking configuration.
type TrackingConfig map[string]TrackingCategory

// TrackingCategory defines the patterns and invalidation behavior for a tracking category.
type TrackingCategory struct {
	Patterns               []string `yaml:"patterns"`
	InvalidateOnFileChange *bool    `yaml:"invalidate_on_file_change,omitempty"`
}

// ShouldInvalidateOnFileChange returns true if this category should be reset when
// the agent modifies files. Defaults to true when not explicitly set.
func (tc TrackingCategory) ShouldInvalidateOnFileChange() bool {
	if tc.InvalidateOnFileChange == nil {
		return true
	}
	return *tc.InvalidateOnFileChange
}

// fileChangeTools are tool names that count as a file modification for invalidation purposes.
var fileChangeTools = map[string]bool{"Edit": true, "Write": true, "NotebookEdit": true}

// IsFileChangeTool returns true if the given tool name is a file-modification tool.
func IsFileChangeTool(toolName string) bool {
	return fileChangeTools[toolName]
}

// GuardRule defines guard checks for a phase transition.
// From and To are phase name strings or "*" for wildcard matching.
type GuardRule struct {
	From     string  `yaml:"from"`
	To       string  `yaml:"to"`
	Disabled bool    `yaml:"disabled,omitempty"`
	Checks   []Check `yaml:"checks"`
}

// Check is a single guard predicate.
type Check struct {
	// Type is one of: evidence, no_active_agents, max_iterations, command_ran
	Type string `yaml:"type"`

	// Key is the evidence map key (used by evidence and command_ran checks).
	Key string `yaml:"key,omitempty"`

	// Value is the expected value (used by evidence check).
	Value string `yaml:"value,omitempty"`

	// Category is used by command_ran to match tracking categories (lint, test).
	Category string `yaml:"category,omitempty"`

	// Alternatives holds additional key/value pairs that also satisfy this check (OR semantics).
	Alternatives []KV `yaml:"alternatives,omitempty"`

	// Message is the denial message returned when this check fails.
	Message string `yaml:"message"`
}

// KV is a key/value pair used in Alternatives.
type KV struct {
	Key   string `yaml:"key"`
	Value string `yaml:"value"`
}

// IdleRule defines checks that must pass when a teammate goes idle.
// Match is a phase name or "*" for wildcard matching.
// Agent is an optional glob pattern matched against the teammate name (case-insensitive).
// If empty, the rule applies to all agents.
type IdleRule struct {
	Match  string  `yaml:"match"`
	Agent  string  `yaml:"agent,omitempty"`
	Checks []Check `yaml:"checks"`
}

package config

// MergeConfigs merges override on top of base, returning a new Config.
// Neither base nor override is mutated.
//
// Merge rules:
//   - tracking: same category key → override replaces base (patterns + flag); new keys append
//   - guards: same from+to → append override checks to base checks;
//     disabled:true in override → remove all rules for that from+to pair
//   - teammate_idle: same match → replace; new match → append
func MergeConfigs(base, override *Config) *Config {
	result := &Config{}

	// Merge tracking — override replaces by key, new keys append
	result.Tracking = mergeTracking(base.Tracking, override.Tracking)

	// Merge guards
	result.Guards = mergeGuards(base.Guards, override.Guards)

	// Merge teammate_idle
	result.TeammateIdle = mergeIdleRules(base.TeammateIdle, override.TeammateIdle)

	return result
}

func mergeTracking(base, override TrackingConfig) TrackingConfig {
	result := make(TrackingConfig)
	for k, v := range base {
		result[k] = v
	}
	for k, v := range override {
		result[k] = v // override replaces base for same key
	}
	return result
}


func mergeGuards(base, override []GuardRule) []GuardRule {
	// Build index of base rules by from+to key
	type key struct{ from, to string }
	index := make(map[key]int)
	result := make([]GuardRule, 0, len(base)+len(override))

	for _, r := range base {
		k := key{r.From, r.To}
		index[k] = len(result)
		result = append(result, r)
	}

	for _, r := range override {
		k := key{r.From, r.To}
		if idx, exists := index[k]; exists {
			if r.Disabled {
				// Remove all rules for this from+to pair
				result[idx] = GuardRule{From: r.From, To: r.To, Disabled: true}
			} else {
				// Deep copy base Checks before appending to avoid mutating the base slice.
				existing := result[idx]
				merged := make([]Check, len(existing.Checks), len(existing.Checks)+len(r.Checks))
				copy(merged, existing.Checks)
				existing.Checks = append(merged, r.Checks...)
				result[idx] = existing
			}
		} else {
			if !r.Disabled {
				index[k] = len(result)
				result = append(result, r)
			}
		}
	}

	// Filter out disabled placeholder entries
	filtered := result[:0]
	for _, r := range result {
		if !r.Disabled {
			filtered = append(filtered, r)
		}
	}
	return filtered
}

func idleRuleKey(r IdleRule) string {
	return r.Match + "|" + r.Agent
}

func mergeIdleRules(base, override []IdleRule) []IdleRule {
	index := make(map[string]int)
	result := make([]IdleRule, 0, len(base)+len(override))

	for _, r := range base {
		index[idleRuleKey(r)] = len(result)
		result = append(result, r)
	}

	for _, r := range override {
		k := idleRuleKey(r)
		if idx, exists := index[k]; exists {
			result[idx] = r // replace
		} else {
			index[k] = len(result)
			result = append(result, r)
		}
	}

	return result
}

