	if err := json.Unmarshal(bytes.TrimSpace(data), &entry); err != nil {
		t.Fatalf("invalid JSON: %v", err)
	}

	if entry["direction"] != "request" {
		t.Errorf("direction = %q, want \"request\"", entry["direction"])
	}
}

